const A=2.2572;

export default function InteractiveParticles({ className = "", style = {}, isHovered: externalIsHovered = false }: InteractiveParticlesProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particlesRef = useRef<Particle[]>([]);
  const animRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let w = container.clientWidth;
    let h = container.clientHeight;
    const dpr = window.devicePixelRatio || 1;

    const resize = () => {
      w = container.clientWidth;
      h = container.clientHeight;
      canvas.width = w * dpr;
      canvas.height = h * dpr;
      canvas.style.width = `${w}px`;
      canvas.style.height = `${h}px`;
      ctx.scale(dpr, dpr);
      if (particlesRef.current.length === 0) init();
    };

    const init = () => {
      // Detect if mobile (you can adjust the breakpoint as needed)
      const isMobile = window.innerWidth < 768;
      
      particlesRef.current = Array.from({ length: L.length }, () => ({
        x: Math.random() * w,
        y: Math.random() * h,
        vx: (Math.random() - 0.5) * 0.2,
        vy: (Math.random() - 0.5) * 0.2,
        targetX: Math.random() * w,
        targetY: Math.random() * h,
        size: isMobile 
          ? Math.random() * 0.5 + 0.1  // Mobile: smaller particles
          : Math.random() * 1.5 + 1.0,  // Desktop: larger particles
        opacity: Math.random() * 0.25 + 0.1,
        targetOpacity: 0.85,
      }));
    };

    resize();
    window.addEventListener("resize", resize);

    const animate = () => {
      ctx.clearRect(0, 0, w, h);

      // Smaller logo — ~55% of height, centered
      let lw = h * 0.55 * A;
      let lh = h * 0.55;
      if (lw > w * 0.65) { lw = w * 0.65; lh = lw / A; }
      const ox = (w - lw) / 2;
      const oy = (h - lh) / 2;

      const particles = particlesRef.current;

      if (externalIsHovered) {
        for (let i = 0; i < particles.length; i++) {
          const p = particles[i];
          const pt = L[i];
          const tx = ox + pt[0] * lw;
          const ty = oy + pt[1] * lh;
          if (!p.assigned) p.assigned = true;
          const dx = tx - p.x, dy = ty - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          const f = Math.min(dist * 0.14, 12);
          if (dist > 0.3) { p.vx += (dx / dist) * f; p.vy += (dy / dist) * f; }
          // Gentle random drift so particles feel alive even when settled
          p.vx += (Math.random() - 0.5) * 0.6;
          p.vy += (Math.random() - 0.5) * 0.6;
          p.vx *= 0.65; p.vy *= 0.65;
          p.opacity += (0.92 - p.opacity) * 0.18;
        }
      } else {
        for (let i = 0; i < particles.length; i++) {
          const p = particles[i];
          p.assigned = false;
          if (Math.abs(p.x - p.targetX) < 8 && Math.abs(p.y - p.targetY) < 8) {
            p.targetX = Math.random() * w;
            p.targetY = Math.random() * h;
            p.targetOpacity = Math.random() * 0.3 + 0.1;
          }
          const dx = p.targetX - p.x, dy = p.targetY - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist > 1) { p.vx += (dx / dist) * 0.04; p.vy += (dy / dist) * 0.04; }
          p.vx += (Math.random() - 0.5) * 0.06;
          p.vy += (Math.random() - 0.5) * 0.06;
          p.vx *= 0.98; p.vy *= 0.98;
          p.opacity += (p.targetOpacity - p.opacity) * 0.03;
          if (p.x < 0 || p.x > w) p.vx *= -0.8;
          if (p.y < 0 || p.y > h) p.vy *= -0.8;
        }
      }

      ctx.fillStyle = "rgb(208, 195, 159)";
      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];
        p.x += p.vx; p.y += p.vy;
        ctx.globalAlpha = p.opacity;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      animRef.current = requestAnimationFrame(animate);
    };

    animate();
    return () => {
      window.removeEventListener("resize", resize);
      if (animRef.current) cancelAnimationFrame(animRef.current);
    };
  }, [externalIsHovered]);

  return (
    <div
      ref={containerRef}
      className={className}
      style={{ position: "absolute", inset: 0, pointerEvents: "none", ...style }}
    >
      <canvas ref={canvasRef} style={{ width: "100%", height: "100%", display: "block" }} />
    </div>
  );
}
